def test_prose_extraction_covers_domain_alignment() -> None:
    # TASK-052: the whole-draft scanner now walks domain_alignment prose in the
    # REAL merged shape — targeted rows carry `{"pk", "rationale"}`, deferred-gap
    # (`*_not_addressed`) rows carry `{"label", "reason"}`. Only `rationale` and
    # `reason` are prose; `label` is a catalogue word and is NOT walked.
    draft = _clean_draft()
    draft["domain_alignment"] = {
        "learner_outcomes_targeted": [{"pk": "1", "rationale": "Targets the reading goal."}],
        "learner_outcomes_not_addressed": [
            {"label": "Some Outcome", "reason": "Deferred to next cycle."}
        ],
    }
    paths = {p for p, _t in _iter_prose_fields(draft)}
    assert "domain_alignment.learner_outcomes_targeted[0].rationale" in paths
    assert "domain_alignment.learner_outcomes_not_addressed[0].reason" in paths
    # The catalogue label is never walked as prose.
    assert not any(p.startswith("domain_alignment.") and p.endswith(".label") for p in paths)


